26	}
27	
28	interface QuoteResult {
29	  premium: number;
30	}
31	
32	const COMPONENT_BASE_PREMIUM = 25;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: COMPONENT_BASE_PREMIUM,
40	  moonstone: COMPONENT_BASE_PREMIUM,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const formsBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const typeBasePremium = (type: string, count: number): number => {
51	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
52	  return count * BASE_PREMIUMS[type];
53	};
54	
55	const policyBasePremium = (items: Item[]): number => {
56	  const counts = new Map<string, number>();
57	  for (const item of items) {
58	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
59	  }
60	  return [...counts].reduce(
61	    (base, [type, count]) => base + typeBasePremium(type, count),
62	    0,
63	  );
64	};
65	
66	// A rate rule contributes its rate to a subject only when it applies.
67	interface RateRule<T> {
68	  applies: (subject: T) => boolean;
69	  rate: number;
70	}
71	
72	const sumApplicableRates = <T>(rules: RateRule<T>[], subject: T): number =>
73	  rules.reduce(
74	    (rate, rule) => (rule.applies(subject) ? rate + rule.rate : rate),
75	    0,
76	  );
77	
78	const CURSE_SURCHARGE = 0.5;
79	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
80	const HIGH_ENCHANTMENT_THRESHOLD = 5;
81	
82	const SURCHARGE_RULES: RateRule<Item>[] = [
83	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
84	  {
85	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
86	    rate: HIGH_ENCHANTMENT_SURCHARGE,
87	  },
88	];
89	
90	const itemSurchargeRate = (item: Item): number =>
91	  sumApplicableRates(SURCHARGE_RULES, item);
92	
93	const itemSurcharge = (item: Item): number =>
94	  itemSurchargeRate(item) * BASE_PREMIUMS[item.type];
95	
96	const itemSurcharges = (items: Item[]): number =>
97	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
98	
99	interface PolicyContext {
100	  customer: Customer;
101	  isFollowUp: boolean;
102	}
103	
104	// Policy-wide modifiers each apply a signed rate to the policy base:
105	// positive rates are surcharges, negative rates are discounts.
106	const POLICY_MODIFIER_RULES: RateRule<PolicyContext>[] = [
107	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
108	  {
109	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
110	    rate: -LOYALTY_DISCOUNT,
111	  },
112	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
113	];
114	
115	const policyModifierRate = (context: PolicyContext): number =>
116	  sumApplicableRates(POLICY_MODIFIER_RULES, context);
117	
118	// Premiums round up (in the MHPCO's favor); toFixed guards against
119	// floating-point error nudging an exact value over an integer boundary.
120	const roundUpPremium = (amount: number): number =>
121	  Math.ceil(Number(amount.toFixed(6)));
122	
123	const quotePremium = (step: QuoteStep, context: PolicyContext): number => {
124	  const { items } = step;
125	  const policyBase = policyBasePremium(items);
126	  // Policy modifiers scale the policy base only; item surcharges are added
127	  // separately (outside the modifier scope), then the flat fee comes last.
128	  const modifiedPolicyBase = policyBase * (1 + policyModifierRate(context));
129	  const total = modifiedPolicyBase + itemSurcharges(items) + PROCESSING_FEE;
130	  return roundUpPremium(total);
131	};
132	
133	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
134	  // Every step is a quote for now, so the first quote is the first step.
135	  // When claim steps interleave, derive isFollowUp from prior quotes instead.
136	  const results = scenario.steps.map((step, index) => {
137	    const isFollowUp = index > 0;
138	    const context: PolicyContext = { customer: scenario.customer, isFollowUp };
139	    return { premium: quotePremium(step, context) };
140	  });
141	  return { results };
142	};
